"use client";
import { useState, useEffect } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import Header from "@/components/Header";
import AboutModal from "@/components/AboutModal";

export default function CatalogPage() {
    const searchParams = useSearchParams();
    const router = useRouter();
    const [search, setSearch] = useState("");
    const [showAbout, setShowAbout] = useState(false);
    const [category, setCategory] = useState(searchParams.get("category") || "all");

    useEffect(() => {
        const cat = searchParams.get("category");
        if (cat) setCategory(cat);
    }, [searchParams]);

    const handleCategory = (catId) => {
        setCategory(catId);
        router.push(`/catalog?category=${catId}`);
    };

    const books = [
        { id: 1, title: "Война и мир", author: "Лев Толстой", year: 2020, genre: "Роман", category: "fiction", available: 2, total: 5, color: "#8B4513", colorLight: "#CD853F" },
        { id: 2, title: "1984", author: "Джордж Оруэлл", year: 2024, genre: "Научная фантастика", category: "fiction", available: 3, total: 6, color: "#1C1C1C", colorLight: "#444444" },
        { id: 3, title: "Мастер и Маргарита", author: "Михаил Булгаков", year: 2021, genre: "Роман", category: "fiction", available: 0, total: 4, color: "#1a1a2e", colorLight: "#3a3a5e" },
        { id: 4, title: "Чистый код", author: "Роберт Мартин", year: 2021, genre: "Программирование", category: "tech", available: 3, total: 4, color: "#0F3460", colorLight: "#1A5276" },
        { id: 5, title: "Sapiens", author: "Юваль Харари", year: 2023, genre: "История", category: "history", available: 2, total: 4, color: "#6B4226", colorLight: "#A0724A" },
        { id: 6, title: "Маленький принц", author: "Сент-Экзюпери", year: 2020, genre: "Сказка", category: "children", available: 5, total: 6, color: "#E8A838", colorLight: "#F4C76B" },
    ];

    const categories = [
        { id: "all", label: "📚 Все книги" },
        { id: "fiction", label: "📖 Художественная" },
        { id: "science", label: "🔬 Научная" },
        { id: "history", label: "🏛️ История" },
        { id: "tech", label: "💻 Технологии" },
        { id: "children", label: "🧸 Детская" },
    ];

    const filtered = books.filter(b => {
        const matchSearch = b.title.toLowerCase().includes(search.toLowerCase()) || b.author.toLowerCase().includes(search.toLowerCase());
        const matchCat = category === "all" || b.category === category;
        return matchSearch && matchCat;
    });

    return (
        <>
            <Header onOpenAbout={() => setShowAbout(true)} />

            <div className="hero">
                <h1>Электронный <span>фонд</span></h1>
                <p>Каталог изданий — более 2 400 книг в вашей библиотеке</p>
            </div>

            <div className="container">
                <div className="profile-card">
                    <div className="avatar large">АК</div>
                    <div className="profile-info">
                        <div className="profile-name">Анна Ковалёва</div>
                        <div className="profile-ticket">Билет №2026-0421 • Читатель</div>
                        <div className="profile-verified">✅ Аккаунт верифицирован</div>
                    </div>
                    <div className="profile-stats">
                        <div className="profile-stat">
                            <div className="profile-stat-value" style={{color:'var(--library-400)'}}>3</div>
                            <div className="profile-stat-label">Активных выдач</div>
                        </div>
                        <div className="profile-stat">
                            <div className="profile-stat-value" style={{color:'var(--purple-400)'}}>2</div>
                            <div className="profile-stat-label">Бронирований</div>
                        </div>
                        <div className="profile-stat">
                            <div className="profile-stat-value" style={{color:'var(--green-400)'}}>0 ₽</div>
                            <div className="profile-stat-label">Штрафы</div>
                        </div>
                    </div>
                </div>

                <div className="search-bar">
                    <div className="search-input-wrap">
                        <svg width="16" height="16" viewBox="0 0 16 16" fill="none" stroke="currentColor"><circle cx="7" cy="7" r="5"/><path d="M11 11L15 15"/></svg>
                        <input className="search-input" placeholder="Поиск по названию, автору, ISBN..." value={search} onChange={e => setSearch(e.target.value)} />
                    </div>
                </div>

                <div className="category-bar">
                    {categories.map(cat => (
                        <button key={cat.id} className={`category-btn ${category === cat.id ? 'active' : ''}`} onClick={() => handleCategory(cat.id)}>{cat.label}</button>
                    ))}
                </div>

                <div className="books-grid">
                    {filtered.map(book => (
                        <div key={book.id} className="book-card">
                            <div className="book-cover" style={{background:`linear-gradient(135deg, ${book.color}33, ${book.color}11)`}}>
                                <div className={`book-badge ${book.available > 0 ? 'badge-available' : 'badge-unavailable'}`}>
                                    {book.available > 0 ? `Доступно: ${book.available}` : 'Нет в наличии'}
                                </div>
                                <div className="book-cover-inner" style={{background:`linear-gradient(135deg, ${book.color}, ${book.colorLight})`}}>
                                    <div className="book-cover-title">{book.title}</div>
                                    <div className="book-cover-author">{book.author.split(' ').slice(-1)[0]}</div>
                                </div>
                            </div>
                            <div className="book-info">
                                <div className="book-title">{book.title}</div>
                                <div className="book-author">{book.author}</div>
                                <div className="book-meta">
                                    <span className="book-genre">{book.genre}</span>
                                    <span className="book-available"><span className={`num ${book.available === 0 ? 'zero' : ''}`}>{book.available}</span> / {book.total}</span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                {filtered.length === 0 && (
                    <div className="empty-state">
                        <div className="empty-state-icon">📚</div>
                        <h3>Книги не найдены</h3>
                        <p>Попробуйте изменить параметры поиска</p>
                    </div>
                )}
            </div>

            {showAbout && <AboutModal onClose={() => setShowAbout(false)} />}
        </>
    );
}